/* eslint-disable @typescript-eslint/no-unused-vars */
import buildDebug from 'debug'

import { createClerkClient, type ClerkClient, type User } from '@clerk/backend'
import { errorUtils, pluginUtils } from '@verdaccio/core'
import { Config, Logger, PackageAccess, RemoteUser } from '@verdaccio/types'

export interface AuthConfig {
  clerk_secret_key?: string
}

const debug = buildDebug('verdaccio:plugin:pro:auth-clerk')

class AuthPlugin extends pluginUtils.Plugin<AuthConfig> implements pluginUtils.Auth<AuthConfig> {
  public config: Config
  public logger: Logger
  private authConfig: AuthConfig
  private clerkClient: ClerkClient

  public constructor(config: AuthConfig, options: pluginUtils.PluginOptions) {
    debug('start auth plugin')

    super(config, options)
    this.config = options.config
    this.logger = options.logger

    this.authConfig = {
      clerk_secret_key: config?.clerk_secret_key || process.env.CLERK_SECRET_KEY,
    }

    if (!this.authConfig.clerk_secret_key) {
      throw errorUtils.getServiceUnavailable(
        '[auth] missing config. Add `clerk_secret_key` to Auth plugin config or use environment variable CLERK_SECRET_KEY',
      )
    }

    this.clerkClient = createClerkClient({ secretKey: this.authConfig.clerk_secret_key })

    debug('Verdaccio Pro Auth plugin is enabled')
  }

  public async authenticate(user: string, password: string, cb: pluginUtils.AuthCallback): Promise<void> {
    debug('authenticate user %o', user)

    try {
      const clerkUser = await this.resolveUser(user)
      if (!clerkUser) {
        debug('user not found')
        return cb(null, false)
      }

      await this.clerkClient.users.verifyPassword({
        userId: clerkUser.id,
        password,
      })

      const groups = await this.getUserGroups(clerkUser, user)
      debug('authentication succeeded!')
      return cb(null, groups)
    }
    catch (error) {
      this.logger.error({ error, user }, 'Clerk sign-in failed for "@{user}": @{error.message}')
      debug('sign-in error %o', error)
      return cb(null, false)
    }
  }

  private async resolveUser(identifier: string): Promise<User | undefined> {
    const { data: byUsername } = await this.clerkClient.users.getUserList({
      username: [identifier],
      limit: 1,
    })

    if (byUsername.length === 1) {
      return byUsername[0]
    }

    const { data: candidates } = await this.clerkClient.users.getUserList({
      query: identifier,
      limit: 10,
    })

    const normalized = identifier.toLowerCase()

    return candidates.find(candidate =>
      candidate.username?.toLowerCase() === normalized
      || candidate.emailAddresses.some(
        email => email.emailAddress.toLowerCase() === normalized,
      ),
    )
  }

  private async getUserGroups(clerkUser: User, loginUser: string): Promise<string[]> {
    const verdaccioUser = clerkUser.username ?? loginUser
    const orgSlugs = new Set<string>()

    const { data: memberships } = await this.clerkClient.users.getOrganizationMembershipList({
      userId: clerkUser.id,
      limit: 100,
    })

    for (const membership of memberships) {
      const slug = membership.organization.slug
      if (slug) {
        orgSlugs.add(slug.startsWith('@') ? slug : `@${slug}`)
      }
    }

    return [verdaccioUser, ...orgSlugs]
  }

  // TODO: email is not part of the Auth interface (yet)
  public async adduser(user: string, password: string, cb: pluginUtils.AuthUserCallback, email?: string): Promise<void> {
    debug('add user %o', user)
    throw errorUtils.getServiceUnavailable('Not supported')
  }

  public async removeUser(user: string): Promise<void> {
    debug('remove user %o', user)
    throw errorUtils.getServiceUnavailable('Not supported')
  }

  public async changePassword(
    user: string,
    oldPassword: string,
    newPassword: string,
    cb: pluginUtils.AuthChangePasswordCallback,
  ): Promise<void> {
    debug('change password for user %o', user)
    throw errorUtils.getServiceUnavailable('Not supported')
  }

  public async allow_access(user: RemoteUser, pkg: PackageAccess, cb: pluginUtils.AuthAccessCallback): Promise<void> {
    debug('allow access for %o', user)
    const access = pkg.access as string[]
    if (access?.includes('$all') || access?.includes('$anonymous')) {
      debug('%o has been granted access', user.name)
      return cb(null, true)
    }

    if (!user.name) {
      const err = errorUtils.getForbidden('not allowed to access package')
      this.logger.debug({ user: user.name }, 'user: @{user} not allowed to access package')
      debug('%o not allowed to access package err', user.name, err.message)
      return cb(err)
    }

    if (access?.includes('$authenticated')) {
      debug('%o has been granted access', user.name)
      return cb(null, true)
    }

    // Groups includes username
    for (const group of user.groups) {
      if (access?.includes(group)) {
        debug('%o has been granted access via group %o', user.name, group)
        return cb(null, true)
      }
    }

    const err = errorUtils.getForbidden('not allowed to access package')
    debug('%o not allowed to access package err', user.name, err.message)
    return cb(err)
  }

  public async allow_publish(user: RemoteUser, pkg: PackageAccess, cb: pluginUtils.AuthAccessCallback): Promise<void> {
    debug('allow publish for %o', user)
    const publish = pkg.publish as string[]
    if (publish?.includes('$all') || publish?.includes('$anonymous')) {
      debug('%o has been granted publish', user.name)
      return cb(null, true)
    }

    if (!user.name) {
      const err = errorUtils.getForbidden('not allowed to publish package')
      this.logger.debug({ user: user.name }, 'user: @{user} not allowed to publish package')
      debug('%o not allowed to publish package err', user.name, err.message)
      return cb(err)
    }

    if (publish?.includes('$authenticated')) {
      debug('%o has been granted publish', user.name)
      return cb(null, true)
    }

    // Groups includes username
    for (const group of user.groups) {
      if (publish?.includes(group)) {
        debug('%o has been granted publish via group %o', user.name, group)
        return cb(null, true)
      }
    }

    const err = errorUtils.getForbidden('not allowed to publish package')
    debug('%o not allowed to publish package err', user.name, err.message)
    return cb(err)
  }

  public async allow_unpublish(user: RemoteUser, pkg: PackageAccess, cb: pluginUtils.AuthAccessCallback): Promise<void> {
    debug('allow unpublish for %o', user)
    const unpublish = pkg.unpublish as string[]
    if (unpublish?.includes('$all') || unpublish?.includes('$anonymous')) {
      debug('%o has been granted unpublish', user.name)
      return cb(null, true)
    }

    if (!user.name) {
      const err = errorUtils.getForbidden('not allowed to unpublish package')
      this.logger.debug({ user: user.name }, 'user: @{user} not allowed to unpublish package')
      debug('%o not allowed to unpublish package err', user.name, err.message)
      return cb(err)
    }

    if (unpublish?.includes('$authenticated')) {
      debug('%o has been granted unpublish', user.name)
      return cb(null, true)
    }

    // Groups includes username
    for (const group of user.groups) {
      if (unpublish?.includes(group)) {
        debug('%o has been granted unpublish via group %o', user.name, group)
        return cb(null, true)
      }
    }

    const err = errorUtils.getForbidden('not allowed to unpublish package')
    debug('%o not allowed to unpublish package err', user.name, err.message)
    return cb(err)
  }
}

export default AuthPlugin
